	}
	cfg := domain.ExpiryConfig{
		DefaultWindowDays: 90,
		MinWindowDays:     7,
		MaxWindowDays:     365,
	}

	record := engine.CertifyUnit(unit, rules, ev, cfg, time.Now())

	if record.Status == domain.StatusCertified {
		t.Error("unit with violations should not be certified")
	}
}

