// based on the depth of analysis support available.
package language_tiers

import "strings"

// Tier represents the level of analysis support for a language.
type Tier int

const (
	// TierGeneric is the baseline tier for languages without native-level analysis.
	TierGeneric Tier = 0
	// TierNative is the tier for languages with native structural analysis support.
	TierNative Tier = 1
)

// TierForLanguage returns the analysis tier for a given language identifier.
// Languages with native analysis support (go, typescript, python, rust)
// return TierNative; all others return TierGeneric. Matching is case-insensitive.
func TierForLanguage(lang string) Tier {
	switch strings.ToLower(lang) {
	case "go", "typescript", "python", "rust":
		return TierNative
	default:
		return TierGeneric
	}
}

